code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
readline.question('', (x) => {
    x = parseInt(x);
    if (x % 5 == 0) console.log(x / 5);
    else console.log(Math.floor(x / 5) + 1);
    readline.close();
});
